async fn fuse(&self, sets: Vec<RankedSet>) -> Result<RankedSet> {
        let start = Instant::now();
        let input_count: usize = sets.iter().map(|s| s.candidates.len()).sum();

        // Degenerate cases.
        if sets.is_empty() {
            return Ok(RankedSet {
                candidates: Vec::new(),
                metrics: StageMetrics {
                    stage_name: self.name().to_string(),
                    latency_ms: 0,
                    input_count: 0,
                    output_count: 0,
                    warnings: Vec::new(),
                },
            });
        }

        // Single set: delegate to PassThrough behavior (min-max normalization).
        if sets.len() == 1 {
            let mut result = PassThrough.fuse(sets).await?;
            result.metrics.stage_name = self.name().to_string();
            return Ok(result);
        }

        // Accumulate RRF scores, component scores, and entries in a single map
        // for better cache locality and fewer hash probes.
        struct Accumulator {
            rrf_score: f64,
            components: HashMap<String, f32>,
            entry: Arc<corvia_common::types::KnowledgeEntry>,
        }

        let mut accum: HashMap<uuid::Uuid, Accumulator> = HashMap::new();

        for set in &sets {
            for (rank_0, candidate) in set.candidates.iter().enumerate() {
                let id = candidate.entry.id;
                let rank = (rank_0 + 1) as f64; // 1-indexed
                let rrf_contribution = 1.0 / (self.k as f64 + rank);

